"""
GUAVA EXAMPLE
Type: Inbound
Scenario: Credit Card Activation
"""

import logging
import os

from guava.helpers.openai import IntentRecognizer
from typing_extensions import override
from collections import namedtuple
from guava import logging_utils

import guava

logger = logging.getLogger("guava.examples.demo_inbound")

Customer = namedtuple("Customer", ["name", "ssn", "unactivated_cards"])
CUSTOMER_DB = [Customer("John Smith", 123456789, {6011002980139424: 567})]


def find_customer_by_ssn(ssn: str) -> Customer | None:
    matches = [c for c in CUSTOMER_DB if c.ssn == ssn]
    return matches[0] if len(matches) else None


ORGANIZATION_NAME = "Harper Valley Bank"


class CreditCardActivationController(guava.CallController):
    def __init__(self):
        super().__init__()
        self.intent_recognizer = IntentRecognizer(
            ["activate credit card", "anything else"]
        )
        self.set_persona(
            organization_name=ORGANIZATION_NAME,
            agent_purpose=f"You are a customer service voice agent that activates credit cards for customers of {ORGANIZATION_NAME}.",
        )
        self.read_script(
            f"Hello, thank you for calling the credit card activation line for {ORGANIZATION_NAME}. My name is Grace. Are you here to activate your credit card?"
        )
        self.accept_call()

    @override
    def on_intent(self, intent: str):
        choice = self.intent_recognizer.classify(intent)
        logger.info("Chosen intent: %s", choice)
        if choice == "activate credit card":
            self.activate_credit_card()
        else:
            return "Unfortunately I'm not able to help with that."

    def activate_credit_card(self):
        self.send_instruction(
            "We are starting the credit card activation process, which starts with asking the caller for their social security number."
        )

        while True:
            self.await_task(
                checklist=[
                    guava.Field(
                        description="Could you give me your social security number?",
                        key="social_security_number",
                        field_type="integer",
                        required=True,
                    )
                ],
            )
            ssn = self.get_field("social_security_number")
            customer = find_customer_by_ssn(ssn)

            if customer is None:
                self.send_instruction(
                    "We were unable to identify the customer using the SSN they provided. Let the caller know this, and ask if they have the correct social security number."
                )
            else:
                self.await_task(
                    objective="We were able to identify the customer using the Social Security Number they have provided. We're going to confirm the client's name.",
                    checklist=[
                        guava.Field(
                            description=f"We're going to confirm the client's name. Am I speaking with {customer.name}?",
                            key="is_client",
                            field_type="multiple_choice",
                            choices=["yes", "no"],
                            required=True,
                        ),
                    ],
                )

                if self.get_field("is_client") == "no":
                    self.send_instruction(
                        "We were unable to identify the client's name in our files. Let the caller know this, and re-ask their social security number."
                    )
                else:
                    break

        self.send_instruction(
            "We were able to find the client's name in our files. Proceed to ask for their card number."
        )
        while True:
            self.await_task(
                checklist=[
                    guava.Field(
                        description="Could you read me the digits on the front of your credit card?",
                        key="credit_card_number",
                        field_type="integer",
                        required=True,
                    )
                ],
            )

            card_number = self.get_field("credit_card_number")
            if card_number not in customer.unactivated_cards:
                self.send_instruction(
                    "We were unable to find the matching card number in our system. Let the caller know this, and re-ask for the credit card number."
                )
            else:
                break

        self.send_instruction(
            "We were able to find the matching card number in our system. Let the caller know this, and ask for security code on their card."
        )
        correct_cvv = customer.unactivated_cards[card_number]
        while True:
            self.await_task(
                checklist=[
                    guava.Field(
                        description="To wrap up, could I get the security code on your card?",
                        key="security_code",
                        field_type="integer",
                        required=True,
                    ),
                ],
            )

            security_code = self.get_field("security_code")
            if security_code != correct_cvv:
                self.send_instruction(
                    "We were unable to match the security code to the credit card. Let the caller know this and re-ask for the security code."
                )
            else:
                break

        self.hangup(
            "Explain to the caller that their credit card has now been activated. Thank them for using the bank's services, and hang up."
        )


if __name__ == "__main__":
    logging_utils.configure_logging()

    guava.Client().listen_inbound(
        agent_number=os.environ["GUAVA_AGENT_NUMBER"],
        controller_class=CreditCardActivationController,
    )
